import {
    listAwardAssignments,
    listAwards,
    showAdvancement,
    showAward,
    showBlank,
    useAwardPresentationContext
} from "../api";
import {useQuery} from "@tanstack/react-query";
import {AdvancementStatus, Award, AwardAssignment, AwardPresentationContext, CommonAdvancement} from "../../javaTypes";
import {
    AdvancementEntry,
    assignmentIsPopulated,
    filterAdvancements,
    getAwardLabel,
    sortAndFilterAssignments
} from "../utils";
import {t} from "../../i18n";
import {useEffect, useRef, useState} from "react";
import {moreThanTwoAllianceBreakDescriptions, twoAllianceBreakDescriptions} from "../ViewScript";
import {Button, ListGroup, ToggleButton, ToggleButtonGroup} from "react-bootstrap";
import './PresentAwards.scss';

const placeholderAdvancement = {
    criteria: "",
    teamName: "",
    displayTeam: "",
    team: 0,
    status: AdvancementStatus.NULL
}
const isCloud = window.FIRST_ENV.projectName == 'FTCCloud'

type AwardAssignmentEntry = AwardAssignment & { awardId: string };

function AwardAssignmentPresenter({award, assignment, assignmentCount, stealthMode, active, present}: { award: Award, assignment: AwardAssignmentEntry, assignmentCount: number, stealthMode: boolean, active: boolean, present: () => void }) {
    const [isPeeking, setIsPeeking] = useState(false);
    const containerRef = useRef<HTMLAnchorElement>(null)
    useEffect(() => {
        if(active) {
            containerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [active]);

    return <ListGroup.Item action variant="secondary" active={active} ref={containerRef} onClick={(e) => {
        if((e.target as Element).closest(".peek-btn")) return;
        present();
    }}>
        <b dangerouslySetInnerHTML={{__html: getAwardLabel(award, assignment.series, assignmentCount)}} className={"ml-4"}></b>&nbsp;
        {!stealthMode || isPeeking ? (award.isTeamAward ? assignment.team?.displayNumber + " - " + assignment.team?.name : assignment.name + (assignment.team ? ` (${assignment.team.displayNumber})` : '')) : '<Hidden>'}
        {stealthMode ? <ToggleButtonGroup type="checkbox" value={isPeeking ? [1] : []} onChange={(v) => setIsPeeking(v.includes(1))} className="float-right mr-1 peek-btn">
            <ToggleButton variant="light" value={1} className={"btn-xs"}>Peek</ToggleButton>
        </ToggleButtonGroup> : null}
    </ListGroup.Item>
}

function AwardPresenter({award, assignments, stealthMode, active, activeAssignment, presentEntry}: { award: Award, assignments: AwardAssignmentEntry[], stealthMode: boolean, active: boolean, activeAssignment: AwardAssignmentEntry | null, presentEntry: (entry: Award | AwardAssignmentEntry) => void }) {
    const containerRef = useRef<HTMLAnchorElement>(null)
    useEffect(() => {
        if(active) {
            containerRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
        }
    }, [active]);

    return <>
        <ListGroup.Item action active={active} ref={containerRef} onClick={() => presentEntry(award)}><b dangerouslySetInnerHTML={{__html: award.name}}></b> About Award</ListGroup.Item>

        {sortAndFilterAssignments(award, assignments).map(aa =>
            <AwardAssignmentPresenter key={aa.series} award={award} assignment={aa} assignmentCount={assignments.length} stealthMode={stealthMode} active={activeAssignment == aa} present={() => presentEntry(aa)} />
        )}
    </>
}

function SingleAdvancementPresentation({advancement, stealthMode, active, present, index}: { advancement: CommonAdvancement, stealthMode: boolean, active: boolean, present: () => void, index: number }) {
    const [isPeeking, setIsPeeking] = useState(false);
    return <ListGroup.Item action variant="secondary" active={active} onClick={(e) => {
        if((e.target as Element).closest(".peek-btn")) return;
        present();
    }}>
        <b>#{index}</b> {!stealthMode || isPeeking ? (advancement.displayTeam + ' - ' + advancement.teamName) : '<Hidden>'}
        {stealthMode ? <ToggleButtonGroup type="checkbox" value={isPeeking ? [1] : []} onChange={(v) => setIsPeeking(v.includes(1))} className="float-right mr-1 peek-btn">
            <ToggleButton variant="light" value={1} className={"btn-xs"}>Peek</ToggleButton>
        </ToggleButtonGroup> : null}
    </ListGroup.Item>
}

function AdvancementPresentation({context, stealthMode, activeEntry, presentEntry}: { context: AwardPresentationContext, stealthMode: boolean, activeEntry: CommonAdvancement | null, presentEntry: (entry: CommonAdvancement) => void }) {
    const containerRef = useRef<HTMLAnchorElement>(null)

    if (!context.advancementConfig || context.advancementConfig.advancementCount == 0) {
        return null;
    }
    const applicableAdvancements = filterAdvancements(context.advancements, context.advancementConfig.advancementCount)
    return <>
        <ListGroup.Item variant="primary">Advancement presentation:</ListGroup.Item>
        <ListGroup.Item action active={activeEntry == placeholderAdvancement} ref={containerRef} onClick={() => presentEntry(placeholderAdvancement)}><b>Preview Advancement</b></ListGroup.Item>
        {applicableAdvancements.map((a, idx) => <SingleAdvancementPresentation key={idx} index={idx + 1} advancement={a} stealthMode={stealthMode} active={activeEntry == a} present={() => presentEntry(a)} />)}
    </>;
}

export default function PresentAwards({queryInterval} : {queryInterval?: number}) {
    const awardData = useQuery({
        queryKey: ["awards", window.eventCode],
        queryFn: () => listAwards(window.eventCode)
    })
    const awardAssignmentData = useQuery({
        queryKey: ["awardAssignments", window.eventCode],
        queryFn: async () => {
            const list = await listAwardAssignments(window.eventCode)
            const ret: Record<string, AwardAssignmentEntry[]> = {}
            Object.keys(list).forEach(k => {
                ret[k] = list[k].map(a => ({...a, awardId: k}))
            })
            return ret
        },
        refetchInterval: queryInterval
    })
    const awardPresentationContext = useAwardPresentationContext(window.eventCode, queryInterval);

    const [stealthMode, setStealthMode] = useState(true);
    const [currentEntry, setCurrentEntry] = useState(-1);

    if (awardData.isLoading || awardAssignmentData.isLoading || awardPresentationContext.isLoading || awardData.isPending || awardAssignmentData.isPending || awardPresentationContext.isPending) {
        return <div>{t`Loading...`}</div>
    }
    if(awardData.isError || awardAssignmentData.isError || awardPresentationContext.isError) {
        return <div>{t`Error loading data`}</div>
    }

    const givenAwards = awardData.data.filter(a => awardAssignmentData.data[a.awardId] && awardAssignmentData.data[a.awardId].filter(assignmentIsPopulated).length > 0).toSorted((a, b) => a.displayOrder - b.displayOrder)
    const awardsNotInAnyGroup = givenAwards.filter(a => !awardPresentationContext.data.presentationGroups.some(pg => pg.includes(a.awardTypeId)))
    const chunkedAwards = awardPresentationContext.data.presentationGroups.map(pg => pg.length == 0 ? awardsNotInAnyGroup : givenAwards.filter(a => pg.includes(a.awardTypeId)))

    const orderedEntries = [
        ...(chunkedAwards.flatMap(as => as.flatMap(a => [a, sortAndFilterAssignments(a, awardAssignmentData.data[a.awardId])].flat()))),
        (awardPresentationContext.data.advancementConfig?.advancementCount ? placeholderAdvancement : null),
        ...(filterAdvancements(awardPresentationContext.data.advancements, awardPresentationContext.data.advancementConfig?.advancementCount || 0))
    ].filter(e => e != null);
    const currentEntryDesc = orderedEntries[currentEntry]
    // These properties are chosen to easily differentiate these three types; they are not generic checks
    const currentAward = currentEntryDesc && currentEntryDesc.hasOwnProperty("awardTypeId") ? currentEntryDesc as Award : null;
    const currentAwardAssignment = currentEntryDesc && currentEntryDesc.hasOwnProperty("series") ? currentEntryDesc as AwardAssignmentEntry : null;
    const currentAdvancement = currentEntryDesc && currentEntryDesc.hasOwnProperty("criteria") ? currentEntryDesc as AdvancementEntry : null;

    function presentEntryByIdx(idx: number){
        const entryDesc = orderedEntries[idx]

        if(entryDesc.hasOwnProperty("awardTypeId")) {
            const award = entryDesc as Award;
            showAward(window.eventCode, award.awardId);
        } else if(entryDesc.hasOwnProperty("series")) {
            const awardAssignment = entryDesc as AwardAssignmentEntry;
            showAward(window.eventCode, awardAssignment.awardId, awardAssignment.series);
        } else if(entryDesc.hasOwnProperty("criteria")) {
            const advancement = entryDesc as AdvancementEntry;
            showAdvancement(window.eventCode, advancement.index);
        }
    }

    function presentPrevious() {
        setCurrentEntry((ce) => {
            presentEntryByIdx(ce - 1);
            return ce - 1;
        });
    }

    function presentNext() {
        setCurrentEntry((ce) => {
            let ret = ce + 1;
            if(ce < 0) {
                ret = 0;
            }
            presentEntryByIdx(ret);
            return ret;
        });
    }

    function presentEntry(entry: Award | AwardAssignmentEntry | AdvancementEntry) {
        const idx = orderedEntries.indexOf(entry);
        setCurrentEntry(idx)
        presentEntryByIdx(idx);
    }


    return <div>
        <div className="row justify-content-center">
            <h2 className="text-center col-10">{t`Awards/Advancement Presentation`}</h2>
        </div>
        {isCloud ?
            <div className="row justify-content-center">
                <a href={`/event/${window.eventCode}/awards/display`} target="_blank" rel="noreferrer">
                    {t`Open Awards Display`}
                </a>
            </div> : null}

        <div className="row pt-2 pb-2 sticky-top present-header">
            <div className="col">
                <Button size={"sm"} variant={"secondary"} onClick={presentPrevious} disabled={currentEntry < 1}>
                    <i className="fa fa-arrow-up"></i> {t`Previous`}
                </Button>
            </div>
            <label><input type="checkbox" checked={stealthMode} title="Disable stealth mode to show winners here"
                          onChange={() => setStealthMode((was) => !was)} /> {t`Stealth Mode`}</label>

            <div className="col text-right">
                <Button size={"sm"} variant={"warning"} className={"mr-2"} onClick={() => showBlank(window.eventCode)}>
                    {t`Show Blank/Video`}
                </Button>
                <Button size={"sm"} variant={"secondary"} onClick={presentNext} disabled={currentEntry >= orderedEntries.length - 1}>
                    <i className="fa fa-arrow-down"></i> {t`Next`}
                </Button>
            </div>
        </div>

        <ListGroup>
            {chunkedAwards.map((as, idx) => <>
                <ListGroup.Item variant="primary" key={`award_group_heading_${idx}`}>These awards will be
                        presented {awardPresentationContext.data.allianceCount > 2 ? moreThanTwoAllianceBreakDescriptions[idx] : twoAllianceBreakDescriptions[idx]}:</ListGroup.Item>
                {as.map(a => <AwardPresenter key={a.awardId} award={a} assignments={awardAssignmentData.data[a.awardId]} stealthMode={stealthMode} active={currentAward == a} activeAssignment={currentAwardAssignment} presentEntry={presentEntry}/>)}
            </>)}
            <AdvancementPresentation context={awardPresentationContext.data} stealthMode={stealthMode} activeEntry={currentAdvancement} presentEntry={presentEntry} />
        </ListGroup>
    </div>
}
